VALUES
  ('aboriginal-6f0ba476-moex-00140', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '下列何者為消滅時效不完成之事由？', '["無行為能力人對於他人之權利，於時效期間終止前6個月內，無法定代理人者", "債權人向法院聲請支付命令，於時效期間終止前3個月內，尚未裁定者", "仲裁程序進行中，於時效期間終止前6個月內，不能作成判斷者", "法院核定中之民事調解，於時效期間終止前3個月內，尚未核定者"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "039c851c4821", "answer_pdf_sha1": "f483a53fcf7d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00141', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '17歲甲未經父母同意將代理權授與25歲之乙。該代理權授與之效力如何？', '["有效", "無效", "效力未定", "得撤銷"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "039c851c4821", "answer_pdf_sha1": "f483a53fcf7d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00142', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲承攬乙家中之裝修工程，雙方約定，工程若有遲延，每遲延1日，預先約定應給付違約金新臺 幣3,000元作為損害賠償。下列敘述，何者正確？', '["違約金為要物契約", "違約金為要式契約", "甲與乙所約定之違約金，為最低損害賠償之額度，若實際損害超出所約定之違約金，得另行請 求損害賠償", "甲與乙所約定之違約金，原則上為損害賠償總額預定性質之違約金"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "039c851c4821", "answer_pdf_sha1": "f483a53fcf7d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00143', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '下列關於保證契約補充性之敘述，何者錯誤？', '["保證債務係主債務之一部，具有補充性", "保證人代負履行責任，原則上係以主債務人不履行債務為停止條件", "保證契約本身並非負有停止條件，無待條件成就，保證契約一經成立，即生效力", "保證人於債權人未就主債務人之財產強制執行而無效果前，對於債權人得拒絕清償"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "039c851c4821", "answer_pdf_sha1": "f483a53fcf7d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00144', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '下列關於合夥人退夥之敘述，何者錯誤？', '["合夥人因受監護之宣告，雖有監護人，仍應退夥", "合夥人死亡，縱契約訂明其繼承人得繼承者，仍應退夥", "合夥縱定有存續期間，如合夥人有非可歸責於自己之重大事由，仍得聲明退夥", "合夥未定有存續期間，或經訂明以合夥人中一人之終身，為其存續期間者，各合夥人原則上得 聲明退夥"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "039c851c4821", "answer_pdf_sha1": "f483a53fcf7d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00145', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲向乙租用冷凍庫，每月租金新臺幣3,000元，為期2年，若冷凍庫運轉失常，應由乙負擔修繕 之責。下列敘述，何者錯誤？', '["乙應使租賃物保持其合於所約定之使用收益狀態，因此負擔修繕義務", "甲應通知乙，並催告其修繕", "若乙拒絕修繕時，甲得終止租約，但不得請求損害賠償", "若甲依法自行修繕者，得於租金中扣除修繕費用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "039c851c4821", "answer_pdf_sha1": "f483a53fcf7d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00146', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲無權占有乙所有之A屋，而將A屋出租於丙。何者有依約收取租金之權利？', '["甲為收取權人", "乙為收取權人", "該收取權為甲乙共有", "甲與乙各自有獨立收取權，其一已先行使者，他方即喪失收取權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "039c851c4821", "answer_pdf_sha1": "f483a53fcf7d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00147', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '下列關於委任契約之敘述，何者錯誤？', '["委任為勞務契約", "有償委任，受任人應盡善良管理人之注意義務處理委任事務", "無償委任，受任人應盡一般人之注意義務處理委任事務", "受任人須為委任人處理事務"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "039c851c4821", "answer_pdf_sha1": "f483a53fcf7d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00148', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '下列何者並非最高限額抵押權所擔保原債權之確定事由？', '["債權人拒絕繼續發生債權，債務人請求確定者", "擔保債權之範圍變更，致原債權不繼續發生者", "擔保債權所由發生之法律關係經終止而消滅者", "最高限額抵押權所擔保之債權，清償期屆至者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "039c851c4821", "answer_pdf_sha1": "f483a53fcf7d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00149', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '下列關於發見埋藏物之敘述，何者正確？', '["所謂埋藏物，乃隱藏於他物之中，而其所有人不明之無主動產", "發見埋藏物乃事實行為之性質，故發見人不以有完全行為能力為必要", "埋藏物若係在他人所有之不動產中發見，由不動產所有人取得埋藏物之所有權，發見人則得依 不當得利之規定求償", "發現漂流物、沈沒物或其他因自然力而脫離他人占有之物者，準用關於發見埋藏物之規定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "039c851c4821", "answer_pdf_sha1": "f483a53fcf7d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL)
